mapper.select:
SELECT 'N' AS CHECKED, ROW_NUMBER() OVER (ORDER BY A.WRITE_DATE DESC, A.ATTACH_FILE_SEQ, A.ORDER_NO) AS NO , A.ATTACH_FILE_SEQ, A.ORDER_NO, A.FILE_SEQ, A.FILE_NAME , A.USE_YN, A.FILE_GUBUN, REGEXP_SUBSTR(A.FILE_NAME, '[^.]+$') AS FILE_EXT , NVL(A.FILE_SIZE,0) AS FILE_SIZE, A.WRITER_ID, TO_CHAR(A.WRITE_DATE,'YYYY-MM-DD') AS WRITE_DATE, A.TITLE , A.MASTER_NO, A.TASK_TYPE, A.TASK_CODE , CASE WHEN A.TASK_TYPE='109' THEN '사내절차' ELSE CM.CODE_GROUP_NAME END TASK_TYPE_NAME , CMD.TASK_NAME , EMP.NAME AS WR_NAME , A.WRITE_DATE AS WRITE_DT FROM BIZ_ATTACH_FILE A LEFT JOIN COME_CODE_GROUP CM ON A.TASK_TYPE=CM.CODE_GROUP LEFT JOIN BIZ_TASK CMD ON A.TASK_TYPE = CMD.BIZ_TYPE AND A.TASK_CODE = CMD.TASK_CODE LEFT OUTER JOIN EMPLOYEE EMP ON A.WRITER_ID=EMP.EMPNO WHERE 1 = 1 AND A.USE_YN = 'Y'
AND A.ATTACH_FILE_SEQ = #{attachFileSeq}
AND A.ORDER_NO = #{orderNo}
AND A.MASTER_NO = #{masterNo}
AND A.TASK_TYPE = #{taskType}
AND A.TASK_CODE = #{taskCode}
AND A.FILE_GUBUN = #{fileGubun}
AND A.FILE_GUBUN IN
#{id}
AND UPPER(A.FILE_NAME) LIKE '%' || UPPER(#{fileName}) || '%'
AND UPPER(A.TITLE) LIKE '%' || UPPER(#{title}) || '%'
AND ( UPPER(A.TITLE) LIKE '%' || UPPER(#{title}) || '%' OR UPPER(A.FILE_NAME) LIKE '%' || UPPER(#{fileName}) || '%' )
AND UPPER(A.TITLE) LIKE '%' || UPPER(#{searchText}) || '%' AND UPPER(A.FILE_NAME) LIKE '%' || UPPER(#{searchText}) || '%'
AND TO_CHAR(A.WRITE_DATE,'YYYY-MM-DD') >= #{startDate}
AND TO_CHAR(A.WRITE_DATE,'YYYY-MM-DD') <= #{endDate}

mapper.insert:
INSERT INTO BIZ_ATTACH_FILE
	 ( ATTACH_FILE_SEQ
	 , ORDER_NO
	 , FILE_SEQ
	 , FILE_NAME
	 , MASTER_NO
	 , TASK_TYPE
	 , TASK_CODE
	 , USE_YN
	 , WRITE_DATE
	 , WRITER_ID
	 , FILE_SIZE
	 , FILE_GUBUN
	 , TITLE
	 )
VALUES
     ( #{attachFileSeq}
     , ( SELECT NVL(MAX(ORDER_NO), 0) + 1 FROM BIZ_ATTACH_FILE WHERE ATTACH_FILE_SEQ = #{attachFileSeq} ) 
     , #{fileSeq}
     , #{fileName}
     , #{masterNo}
     , #{taskType}
     , #{taskCode}
     , 'Y'
     , SYSDATE
     , #{writerId}
     , #{fileSize}
     , #{fileGubun}
     , #{title}
     )

mapper.update:
		UPDATE BIZ_ATTACH_FILE
           SET USE_YN = 'N'
             , DELETE_ID = #{writerId}
             , DELETE_DATE = SYSDATE
         WHERE ATTACH_FILE_SEQ = #{attachFileSeq}
           AND ORDER_NO = #{orderNo}
